            }
        }
    }
    return false;
}

pub fn bodyMentionsThis(stmts: std.ArrayList(Stmt)) bool {
    for (stmts.items) |s| {
        if (stmtMentionsThis(s)) {
            return true;
        }
    }
    return false;
}

pub fn typeRefStr(tr: TypeRef) []const u8 {
    switch (tr) {
