            return _str_concat("?", typeRefStr(inner), _allocator);
        },
        .error_union => |_ptr_inner| {
            const inner = _ptr_inner.*;
            return _str_concat("!", typeRefStr(inner), _allocator);
        },
        .ref_to => |_ptr_inner| {
            const inner = _ptr_inner.*;
            return _str_concat("^", typeRefStr(inner), _allocator);
