                            }
                        }
                    }
                }
            },
            .struct_ => |_ptr_s| {
                const s = _ptr_s.*;
                g.struct_names.add(s.name);
            },
            else => |_| {
                // pass
            },
        }
    }
    for (m.decls.items) |decl| {
        switch (decl) {
            .use_ => |_ptr_u| {
                const u = _ptr_u.*;
                g.genUse(u);
            },
            .enum_ => |_ptr_e| {
                const e = _ptr_e.*;
                g.genEnum(e);
            },
            .union_ => |_ptr_u| {
                const u = _ptr_u.*;
                g.genUnion(u);
            },
            .struct_ => |_ptr_s| {
                const s = _ptr_s.*;
                g.genStruct(s);
            },
            .class_ => |_ptr_c| {
                const c = _ptr_c.*;
                g.genClass(c);
            },
            .method => |_ptr_mth| {
                const mth = _ptr_mth.*;
                g.genMethod(mth);
            },
            .var_ => |_ptr_v| {
