                g.genFieldDecl(v);
            },
            .sig_ => |_ptr_s2| {
                const s2 = _ptr_s2.*;
                g.genSig(s2);
            },
            .namespace_ => |_ptr_ns| {
                const ns = _ptr_ns.*;
                g.genNamespace(ns);
            },
            .interface_ => |_ptr_ifc| {
