        sb.appendSlice(_allocator, "        }\n") catch @panic("OOM");
        sb.appendSlice(_allocator, "        std.process.exit(1);\n") catch @panic("OOM");
        sb.appendSlice(_allocator, "    };\n") catch @panic("OOM");
