    pub fn zigPrimitive(self: *Generator, name: []const u8) []const u8 {
        _ = self;
        if (std.mem.eql(u8, name, "int")) {
            return "i64";
        }
        if (std.mem.eql(u8, name, "uint")) {
            return "u64";
        }
        if (std.mem.eql(u8, name, "float")) {
