        if (std.mem.eql(u8, name, "uint8")) {
            return "u8";
        }
        if (std.mem.eql(u8, name, "uint16")) {
            return "u16";
        }
        if (std.mem.eql(u8, name, "uint32")) {
            return "u32";
        }
        if (std.mem.eql(u8, name, "uint64")) {
            return "u64";
        }
        if (std.mem.eql(u8, name, "uint128")) {
            return "u128";
        }
        if (std.mem.eql(u8, name, "byte")) {
