    pub fn genUse(self: *Generator, n: DeclUse) void {
        const alias: []const u8 = n.path;
        const has_same_named_class = self.class_names.contains_(alias);
        if ((@as(i64, @intCast(n.exposed.items.len)) == 0)) {
            self.w.emit("const ");
            self.w.emit(alias);
            self.w.emit(" = @import(\"");
            self.w.emit(n.path);
            self.w.emit(".zig\")");
            if (has_same_named_class) {
                self.w.emit(".");
                self.w.emit(alias);
                self.unwrapped_imports.add(alias);
            }
            self.w.emit(";\n");
        } else {
            self.w.emit("const ");
            self.w.emit(alias);
            self.w.emit(" = @import(\"");
            self.w.emit(n.path);
            self.w.emit(".zig\");\n");
            var i: i64 = 0;
            while (_zebra_lt(i, @as(i64, @intCast(n.exposed.items.len)))) {
                const ename: []const u8 = n.exposed.items[@intCast(i)];
                if (!std.mem.eql(u8, ename, alias)) {
                    self.w.emit("const ");
                    self.w.emit(ename);
                    self.w.emit(" = ");
                    self.w.emit(alias);
                    self.w.emit(".");
                    self.w.emit(ename);
                    self.w.emit(";\n");
                }
                i = (i + 1);
            }
        }
    }

