    pub fn genMethod(self: *Generator, m: DeclMethod) void {
        self.writeIndent();
        self.w.emit("pub fn ");
        self.w.emit(m.name);
        self.w.emit("(");
        const has_self = (!std.mem.eql(u8, self.owner, "") and (!m.mods.is_shared));
        if (has_self) {
            if (self.is_generic) {
