                        },
                    }
                }
            }
            if ((((has_self and (!bodyMentionsThis(mstmts))) and (!bodyUsesAnyField(mstmts, self.owner_members))) and (!bodyUsesAnyMethod(mstmts, self.owner_members)))) {
                bg.line("_ = self;");
